functions.example_code:
// 查找所有 Person 节点
MATCH (p:Person)
RETURN p.name, p.age

// 查找 Alice 的朋友
MATCH (a:Person {name: 'Alice'})-[:KNOWS]->(friend:Person)
RETURN friend.name

// 创建一个 Person 节点
CREATE (p:Person {name: 'Alice', age: 30})
RETURN p

// 同时创建两个节点和它们之间的关系
CREATE (a:Person {name: 'Bob'})-[:KNOWS]->(b:Person {name: 'Charlie'})

// 把每个人的所有朋友名字收集为一个列表
MATCH (p:Person)-[:KNOWS]->(friend:Person)
RETURN p.name AS person, collect(friend.name) AS friends

// 列出 Alice 到 David 最短路径上的所有节点
MATCH p = shortestPath((a:Person {name:'Alice'})-[*..6]-(d:Person {name:'David'}))
RETURN nodes(p) AS path_nodes

// 列出最短路径上经过的关系类型
MATCH p = shortestPath((a:Person {name:'Alice'})-[*..6]-(d:Person {name:'David'}))
RETURN [r IN relationships(p) | type(r)] AS rel_types

// 生成 1..10 的列表
RETURN range(1, 10) AS nums

// 生成 0,2,4,...,10
RETURN range(0, 10, 2) AS evens

// 取每个人收藏的第一个标签
MATCH (p:Person)
RETURN p.name, head(p.tags) AS first_tag

// 取最短路径上最后一个节点（即终点）
MATCH p = shortestPath((a:Person {name:'Alice'})-[*..6]-(d:Person {name:'David'}))
RETURN last(nodes(p)) AS end_node

// 列出 Alice 的所有外向关系类型
MATCH (a:Person {name:'Alice'})-[r]->()
RETURN DISTINCT type(r) AS rel_type

// 查看 Alice 节点的所有属性
MATCH (a:Person {name:'Alice'})
RETURN properties(a) AS props

// 把所有人名转换为大写返回
MATCH (p:Person)
RETURN toUpper(p.name) AS upper_name

// 当前日期
RETURN date() AS today

// 从字符串解析
RETURN date('2026-06-18') AS d

// 从 Map 构造
RETURN date({year: 2026, month: 6, day: 18}) AS d2

// 当前时间
RETURN datetime() AS now

// ISO 字符串解析（带时区）
RETURN datetime('2026-06-18T10:30:00+08:00') AS dt

// 1 天 2 小时
RETURN duration('P1DT2H') AS d

// 用 Map 构造
RETURN duration({days: 1, hours: 2, minutes: 30}) AS d2

// 与 date 相加
RETURN date('2026-06-18') + duration('P7D') AS next_week
